"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { useRouter } from "next/navigation";
import InsightsLoading from "./loading";

interface ConceptInsight {
  label: string;
  confidence_state: string;
  document_title: string;
}

export default function InsightsPage() {
  const supabase = createClient();
  const router = useRouter();
  const [insights, setInsights] = useState<ConceptInsight[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<"all" | "low" | "medium" | "high">("all");

  useEffect(() => {
    async function load() {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { router.push("/auth/login"); return; }

      const { data: perfData } = await supabase
        .from("concept_performance")
        .select(`
          confidence_state,
          concept_id,
          concepts:concept_id (label, document_id, documents:document_id (title))
        `)
        .eq("user_id", user.id)
        .neq("confidence_state", "unseen");

      const mapped: ConceptInsight[] = (perfData ?? []).map((p: Record<string, unknown>) => {
        const concepts = p.concepts as Record<string, unknown> | null;
        const documents = concepts?.documents as Record<string, unknown> | null;
        return {
          label: (concepts?.label as string) ?? "Unknown",
          confidence_state: p.confidence_state as string,
          document_title: (documents?.title as string) ?? "Unknown",
        };
      });

      setInsights(mapped);
      setLoading(false);
    }
    load();
  }, []);

  const filtered = filter === "all"
    ? insights
    : insights.filter((i) => i.confidence_state === filter);

  const counts = {
    high: insights.filter((i) => i.confidence_state === "high").length,
    medium: insights.filter((i) => i.confidence_state === "medium").length,
    low: insights.filter((i) => i.confidence_state === "low").length,
  };

  if (loading) return <InsightsLoading />;

  return (
    <div style={{
      width: "100%", padding: "1rem 0",
      minHeight: "calc(100dvh - 5rem)",
    }}>
      <h1 className="text-headline-md" style={{ marginBottom: "2rem" }}>
        Insights
      </h1>

      <div className="flex flex-col md:flex-row gap-8 items-start">
        {/* Left pane: Summary & Filters */}
        <div className="w-full md:w-1/3 flex flex-col gap-6" style={{ position: "sticky", top: "2rem" }}>
          
          <div className="aether-card" style={{ padding: "1.5rem" }}>
            <h2 className="text-title-lg" style={{ marginBottom: "1rem" }}>Summary</h2>
            <div style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="var(--color-primary-bright)"><circle cx="12" cy="12" r="10" /></svg>
                  <span className="text-body-lg" style={{ fontWeight: 500 }}>Strong</span>
                </div>
                <span style={{ fontFamily: "var(--font-headline)", fontSize: "1.5rem", fontWeight: 700, color: "var(--color-primary-bright)" }}>
                  {counts.high}
                </span>
              </div>
              
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="var(--color-secondary)"><rect x="3" y="3" width="18" height="18" rx="3" /></svg>
                  <span className="text-body-lg" style={{ fontWeight: 500 }}>Developing</span>
                </div>
                <span style={{ fontFamily: "var(--font-headline)", fontSize: "1.5rem", fontWeight: 700, color: "var(--color-secondary)" }}>
                  {counts.medium}
                </span>
              </div>

              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="var(--color-error)"><path d="M12 2L22 20H2L12 2Z" /></svg>
                  <span className="text-body-lg" style={{ fontWeight: 500 }}>Needs review</span>
                </div>
                <span style={{ fontFamily: "var(--font-headline)", fontSize: "1.5rem", fontWeight: 700, color: "var(--color-error)" }}>
                  {counts.low}
                </span>
              </div>
            </div>
          </div>

          <div className="aether-card" style={{ padding: "1.5rem" }}>
            <h2 className="text-title-lg" style={{ marginBottom: "1rem" }}>Filter</h2>
            <div style={{ display: "flex", flexWrap: "wrap", gap: "0.75rem" }}>
              {(["all", "high", "medium", "low"] as const).map((f) => (
                <button
                  key={f}
                  className={filter === f ? "btn-primary" : "btn-secondary"}
                  onClick={() => setFilter(f)}
                  style={{ 
                    flex: "1 0 calc(50% - 0.75rem)",
                    fontSize: "0.875rem", 
                    padding: "0.6rem 1rem", 
                    textTransform: "capitalize",
                    display: "flex",
                    justifyContent: "center",
                    gap: "0.5rem"
                  }}
                >
                  {f === "high" && <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="12" r="10" /></svg>}
                  {f === "medium" && <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><rect x="3" y="3" width="18" height="18" rx="3" /></svg>}
                  {f === "low" && <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2L22 20H2L12 2Z" /></svg>}
                  {f === "all" && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon></svg>}
                  {f}
                </button>
              ))}
            </div>
          </div>

        </div>

        {/* Right pane: Concept list */}
        <div className="w-full md:w-2/3">
          {filtered.length === 0 ? (
            <div className="aether-card" style={{
              textAlign: "center", padding: "4rem 2rem",
              background: "transparent", border: "2px dashed var(--color-outline-variant)"
            }}>
              <p className="text-body-lg" style={{ color: "var(--color-on-surface-variant)" }}>
                {insights.length === 0
                  ? "Complete a session to see your insights"
                  : "No concepts in this category"}
              </p>
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: "0.875rem" }}>
              {filtered.map((insight, i) => {
                let glowColor = "transparent";
                if (insight.confidence_state === "high") glowColor = "rgba(99, 137, 255, 0.1)";
                else if (insight.confidence_state === "medium") glowColor = "rgba(158, 158, 158, 0.1)";
                else if (insight.confidence_state === "low") glowColor = "rgba(236, 124, 138, 0.1)";

                return (
                  <div
                    key={i}
                    className="aether-card"
                    style={{
                      display: "flex", alignItems: "center", gap: "1rem", 
                      padding: "1.25rem",
                      backgroundColor: glowColor,
                      borderLeft: insight.confidence_state === "high" ? "4px solid var(--color-primary-bright)" 
                                : insight.confidence_state === "medium" ? "4px solid var(--color-secondary)"
                                : "4px solid var(--color-error)",
                    }}
                  >
                    <div style={{ 
                      flexShrink: 0, 
                      color: insight.confidence_state === "high" ? "var(--color-primary-bright)" 
                           : insight.confidence_state === "medium" ? "var(--color-secondary)"
                           : "var(--color-error)",
                      display: "flex", alignItems: "center", justifyContent: "center",
                      backgroundColor: "var(--color-surface)",
                      width: "48px", height: "48px", borderRadius: "var(--radius-input)"
                    }}>
                      {insight.confidence_state === "high" && <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="12" r="10" /></svg>}
                      {insight.confidence_state === "medium" && <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><rect x="3" y="3" width="18" height="18" rx="3" /></svg>}
                      {insight.confidence_state === "low" && <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2L22 20H2L12 2Z" /></svg>}
                    </div>

                    <div style={{ flex: 1 }}>
                      <p style={{
                        fontFamily: "var(--font-headline)", fontSize: "1.125rem",
                        fontWeight: 600, color: "var(--color-on-surface)",
                        marginBottom: "0.25rem"
                      }}>
                        {insight.label}
                      </p>
                      <p style={{
                        fontFamily: "var(--font-label)", fontSize: "0.8125rem",
                        color: "var(--color-secondary-text)", textTransform: "uppercase",
                        letterSpacing: "0.05em", fontWeight: 500
                      }}>
                        {insight.document_title}
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import LibraryLoading from "./loading";
import Link from "next/link";

interface DocumentWithProgress {
  id: string;
  title: string;
  status: string;
  total_concepts: number;
  created_at: string;
  concepts_covered: number;
  bytes?: number;
}

export default function LibraryPage() {
  const router = useRouter();
  const supabase = createClient();
  const [documents, setDocuments] = useState<DocumentWithProgress[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function loadDocuments() {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { router.push("/auth/login"); return; }

      const { data: docs } = await supabase
        .from("documents")
        .select("*")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false });

      if (!docs) { setLoading(false); return; }

      const docsWithProgress: DocumentWithProgress[] = [];
      for (const doc of docs) {
        const { count } = await supabase
          .from("concept_performance")
          .select("*", { count: "exact", head: true })
          .eq("user_id", user.id)
          .eq("document_id", doc.id)
          .in("confidence_state", ["medium", "high"]);

        docsWithProgress.push({
          ...doc,
          concepts_covered: count ?? 0,
        });
      }

      setDocuments(docsWithProgress);
      setLoading(false);
    }

    loadDocuments();
  }, [router, supabase]);

  const handleDelete = async (e: React.MouseEvent, docId: string) => {
    e.stopPropagation();
    e.preventDefault();
    if (!window.confirm("Are you sure you want to delete this document?")) return;

    setDocuments((prev) => prev.filter((d) => d.id !== docId));
    try {
      await supabase.from("concept_performance").delete().eq("document_id", docId);
      await supabase.from("concepts").delete().eq("document_id", docId);
      await supabase.from("documents").delete().eq("id", docId);
    } catch (err) {
      console.error("Failed to delete", err);
    }
  };

  if (loading) return <LibraryLoading />;

  return (
    <div style={{
      width: "100%", 
      minHeight: "100vh",
      display: "flex",
      flexDirection: "column"
    }}>
      {/* HEADER */}
      <div style={{
        display: "flex", justifyContent: "space-between", alignItems: "center",
        marginBottom: "3rem",
      }}>
        <h1 className="text-headline-md" style={{ color: "var(--color-primary)", fontWeight: 700 }}>Library</h1>
        <div style={{ display: "flex", gap: "1.5rem", color: "var(--color-on-surface-variant)" }}>
          <button style={{ background: "none", border: "none", color: "inherit", cursor: "pointer" }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
          </button>
          <button style={{ background: "none", border: "none", color: "inherit", cursor: "pointer" }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg>
          </button>
          <button style={{ background: "none", border: "none", color: "inherit", cursor: "pointer" }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="3"></circle><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"></path></svg>
          </button>
        </div>
      </div>

      {/* STORAGE CAPACITY */}
      <div style={{ marginBottom: "2rem" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: "0.75rem" }}>
          <div>
            <p style={{ fontSize: "0.7rem", fontWeight: 700, letterSpacing: "1px", color: "var(--color-on-surface-variant)", textTransform: "uppercase", marginBottom: "0.25rem" }}>Storage Capacity</p>
            <h2 style={{ fontSize: "1.5rem", fontWeight: 700, color: "var(--color-on-surface)", letterSpacing: "-0.5px" }}>Cognitive Load: 42%</h2>
          </div>
          <p style={{ fontSize: "0.7rem", fontWeight: 700, letterSpacing: "1px", color: "var(--color-on-surface-variant)", textTransform: "uppercase" }}>
            {documents.length} OF 150 DOCUMENTS
          </p>
        </div>
        <div style={{ height: "4px", width: "100%", background: "var(--color-outline-variant)", display: "flex", borderRadius: "2px", overflow: "hidden" }}>
          <div style={{ width: "42%", background: "var(--color-primary)", height: "100%" }} />
        </div>
      </div>

      {/* DOCUMENT GRID */}
      <div style={{ 
        display: "grid", 
        gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", 
        gap: "1.5rem",
        marginBottom: "3rem"
      }}>
        {documents.map((doc) => {
          const isReady = doc.status === "ready";
          const isFailed = doc.status === "failed" || doc.status === "unsupported";
          const isProcessing = doc.status === "processing";

          const bytes = doc.bytes || (Math.random() * 15 * 1024 * 1024 + 1024 * 1024);
          const mbSize = (bytes / (1024 * 1024)).toFixed(1);

          return (
            <div
              key={doc.id}
              onClick={() => isReady && router.push(`/session/${doc.id}`)}
              style={{
                backgroundColor: "var(--color-surface-container)",
                borderRadius: "12px",
                padding: "1.5rem",
                display: "flex",
                flexDirection: "column",
                justifyContent: "space-between",
                minHeight: "220px",
                cursor: isReady ? "pointer" : "default",
                transition: "transform 0.2s ease, background-color 0.2s ease",
              }}
              onMouseOver={(e) => { if (isReady) { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.backgroundColor = "var(--color-surface-container-high)"; } }}
              onMouseOut={(e) => { if (isReady) { e.currentTarget.style.transform = "none"; e.currentTarget.style.backgroundColor = "var(--color-surface-container)"; } }}
            >
              <div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "1.25rem" }}>
                  <div style={{ color: isFailed ? "var(--color-error)" : "var(--color-primary-bright)" }}>
                    {isFailed ? (
                      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>
                    ) : (
                      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
                    )}
                  </div>
                  <div style={{
                    padding: "4px 12px",
                    borderRadius: "100px",
                    backgroundColor: isFailed ? "var(--color-error-container)" : "var(--color-primary-container)",
                    color: isFailed ? "var(--color-error)" : "var(--color-primary-bright)",
                    fontSize: "0.65rem",
                    fontWeight: 800,
                    letterSpacing: "1px",
                    textTransform: "uppercase"
                  }}>
                    {doc.status}
                  </div>
                </div>

                <h3 style={{ fontSize: "1.125rem", fontWeight: 700, color: "var(--color-on-surface)", marginBottom: "0.25rem", lineHeight: 1.4 }}>
                  {doc.title}
                </h3>
                <p style={{ fontSize: "0.75rem", color: "var(--color-on-surface-variant)", opacity: 0.8 }}>
                  {isFailed ? "Corrupt file format detected" : `Archived ${new Date(doc.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} • ${mbSize} MB`}
                </p>
              </div>

              <div style={{ marginTop: "1.5rem", display: "flex", alignItems: "flex-end", justifyContent: "space-between", height: "32px" }}>
                {isProcessing ? (
                  <div style={{ display: "flex", alignItems: "center", gap: "1rem", width: "100%" }}>
                    <div style={{ height: "4px", flex: 1, backgroundColor: "var(--color-surface-container-high)", borderRadius: "2px", overflow: "hidden" }}>
                      <div style={{ width: "67%", height: "100%", backgroundColor: "var(--color-primary)" }} />
                    </div>
                    <span style={{ fontSize: "0.75rem", fontWeight: 700, color: "var(--color-on-surface)" }}>67%</span>
                  </div>
                ) : isReady ? (
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%" }}>
                    <div style={{ display: "flex", gap: "0.5rem" }}>
                      <span style={{ padding: "4px 8px", backgroundColor: "var(--color-surface)", color: "var(--color-on-surface-variant)", fontSize: "0.65rem", borderRadius: "4px" }}>Psychology</span>
                      <span style={{ padding: "4px 8px", backgroundColor: "var(--color-surface)", color: "var(--color-on-surface-variant)", fontSize: "0.65rem", borderRadius: "4px" }}>Research</span>
                    </div>
                    <div style={{ color: "var(--color-on-surface-variant)" }}>
                      <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" strokeWidth="1"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>
                    </div>
                  </div>
                ) : isFailed ? (
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%" }}>
                    <span style={{ fontSize: "0.75rem", fontWeight: 800, color: "var(--color-error)", textTransform: "uppercase", letterSpacing: "1px" }}>Retry Upload</span>
                    <button onClick={(e) => handleDelete(e, doc.id)} style={{ background: "none", border: "none", color: "var(--color-on-surface-variant)", cursor: "pointer" }}>
                      <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2M10 11v6M14 11v6"/></svg>
                    </button>
                  </div>
                ) : null}
              </div>
            </div>
          );
        })}

        {/* DROPZONE CARD */}
        <div style={{
          border: "2px dashed var(--color-surface-container-highest)",
          borderRadius: "12px",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          minHeight: "220px",
          cursor: "pointer",
          transition: "background 0.2s ease"
        }}
        onClick={() => router.push("/upload")}
        onMouseOver={(e) => e.currentTarget.style.backgroundColor = "var(--color-surface-container)"}
        onMouseOut={(e) => e.currentTarget.style.backgroundColor = "transparent"}
        >
          <div style={{ width: "40px", height: "40px", borderRadius: "8px", backgroundColor: "var(--color-surface-container)", display: "flex", alignItems: "center", justifyContent: "center", marginBottom: "1rem", color: "var(--color-primary-bright)" }}>
             <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="12" y1="18" x2="12" y2="12"></line><line x1="9" y1="15" x2="12" y2="12"></line><line x1="15" y1="15" x2="12" y2="12"></line></svg>
          </div>
          <p style={{ fontSize: "0.875rem", fontWeight: 700, color: "var(--color-on-surface-variant)" }}>Drop new documents here</p>
        </div>
      </div>

      {/* BOTTOM WIDGETS */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr", gap: "1.5rem", marginTop: "auto" }}>

        {/* We use a media query trick via flex-wrap or just hardcode grid layout based on screen. Since we want a robust layout, let's use flex or CSS Grid */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))", gap: "1.5rem" }}>

          {/* WEEKLY INSIGHT (Takes up 2/3 roughly if enough space) */}
          <div style={{ gridColumn: "span 2", backgroundColor: "var(--color-surface-container)", borderRadius: "16px", padding: "2.5rem", display: "flex", flexDirection: "column", justifyContent: "space-between", minHeight: "220px" }}>
            <div>
              <h2 style={{ fontSize: "1.75rem", fontWeight: 700, color: "var(--color-on-surface)", marginBottom: "0.75rem", letterSpacing: "-0.5px" }}>Weekly Insight</h2>
              <p style={{ color: "var(--color-on-surface-variant)", fontSize: "0.875rem", maxWidth: "80%", lineHeight: 1.6 }}>
                You processed 12 complex documents this week with a focus retention rate of 88%. This is 12% higher than your monthly average.
              </p>
            </div>
